use anchor_lang::prelude::*;
use anchor_spl::token::{Mint, Token, TokenAccount};

// === constants.rs ===

/// Approximate slots in one day at 400ms/slot (~24h).
/// Actual wall-clock time varies ±10% due to slot rate fluctuation.
pub const SLOTS_PER_DAY: u64 = 216_000;

pub const OPERATOR_CONFIG_SEED: &[u8] = b"operator_config";
pub const CUSTOMER_BALANCE_SEED: &[u8] = b"customer_balance";
pub const TASK_RECEIPT_SEED: &[u8] = b"task_receipt";
pub const VAULT_SEED: &[u8] = b"vault";

// === state/operator_config.rs ===

/// Global program configuration controlled by the operator.
/// PDA seeds: [OPERATOR_CONFIG_SEED]
#[account]
pub struct OperatorConfig {
    /// Wallet authorized to settle tasks, refund, pause/unpause
    pub authority: Pubkey,
    /// Revenue destination token account
    pub treasury: Pubkey,
    /// SPL token mint accepted by this program (e.g., USDC)
    pub mint: Pubkey,
    /// Protocol fee in basis points (500 = 5%, max 10_000)
    pub protocol_fee_bps: u16,
    /// Circuit breaker — when true, blocks deposits and settlements
    pub paused: bool,
    /// PDA bump seed
    pub bump: u8,
}
// INIT_SPACE: 32 + 32 + 32 + 2 + 1 + 1 = 100

// === state/customer_balance.rs ===

/// Per-customer on-chain balance and spending configuration.
/// PDA seeds: [CUSTOMER_BALANCE_SEED, customer.key().as_ref()]
#[account]
pub struct CustomerBalance {
    pub customer: Pubkey,
    pub balance: u64,
    pub total_deposited: u64,
    pub total_spent: u64,
    pub task_count: u64,
    pub max_per_task: u64,
    pub max_per_day: u64,
    pub daily_spent: u64,
    pub daily_reset_slot: u64,
    pub created_at: i64,
    pub bump: u8,
}
// INIT_SPACE: 32 + (8 * 8) + 8 + 1 = 105

// === state/task_receipt.rs ===

#[derive(AnchorSerialize, AnchorDeserialize, Clone, PartialEq, Eq)]
pub enum TaskStatus {
    Settled,
    Refunded,
    Disputed,
}

/// Immutable on-chain settlement receipt.
/// PDA seeds: [TASK_RECEIPT_SEED, &task_id_hash]
#[account]
pub struct TaskReceipt {
    /// SHA-256 of the human-readable task_id string
    pub task_id_hash: [u8; 32],
    pub customer: Pubkey,
    pub amount: u64,
    /// Computed fee: amount * protocol_fee_bps / 10_000
    pub fee_amount: u64,
    /// SHA-256 of the off-chain receipt JSON
    pub receipt_hash: [u8; 32],
    pub operator: Pubkey,
    pub settled_at: i64,
    pub status: TaskStatus,
    pub bump: u8,
}
// INIT_SPACE: 32 + 32 + 8 + 8 + 32 + 32 + 8 + 1 + 1 = 154

// === errors.rs ===

#[error_code]
pub enum CtoPayError {
    #[msg("Program is paused")]
    ProgramPaused,
    #[msg("Insufficient balance")]
    InsufficientBalance,
    #[msg("Amount exceeds per-task spending cap")]
    SpendingCapPerTaskExceeded,
    #[msg("Amount exceeds daily spending cap")]
    SpendingCapDailyExceeded,
    #[msg("Unauthorized operator")]
    UnauthorizedOperator,
    #[msg("Unauthorized customer")]
    UnauthorizedCustomer,
    #[msg("Task already settled")]
    TaskAlreadySettled,
    #[msg("Task not in settled state for refund")]
    TaskNotSettled,
    #[msg("Arithmetic overflow")]
    ArithmeticOverflow,
    #[msg("Invalid mint")]
    InvalidMint,
    #[msg("Amount must be greater than zero")]
    ZeroAmount,
    #[msg("Invalid protocol fee basis points (must be <= 10000)")]
    InvalidFeeBps,
}

